import React, { useEffect, useState } from 'react';
import api from '../api';

const AppointmentList = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [doctors, setDoctors] = useState<any[]>([]);
  
  // Form States
  const [selectedPatient, setSelectedPatient] = useState('');
  const [selectedDoctor, setSelectedDoctor] = useState('');
  const [appDate, setAppDate] = useState('');
  const [status, setStatus] = useState('Pending');

  const fetchData = async () => {
    try {
      const [resApp, resPat, resDoc] = await Promise.all([
        api.get('appointments/'),
        api.get('patients/'),
        api.get('doctors/')
      ]);
      setAppointments(resApp.data);
      setPatients(resPat.data);
      setDoctors(resDoc.data);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // KINI ANG SAKTONG PAYLOAD PARA SA IMONG MODELS.PY
      await api.post('appointments/', {
        patient: selectedPatient,      // ID sa Patient
        doctor: selectedDoctor,        // ID sa Doctor
        appointment_date: appDate,     // Saktong field name
        status: status
      });
      fetchData();
      alert("Appointment Scheduled!");
    } catch (err: any) {
      console.error("Error details:", err.response?.data);
      alert("Error: Check if Patient/Doctor ID is correct.");
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-2 md:grid-cols-5 gap-2 bg-gray-50 p-4 rounded-lg shadow-sm">
        {/* Dropdown para sa Patient */}
        <select className="border p-2 rounded" value={selectedPatient} onChange={e => setSelectedPatient(e.target.value)} required>
          <option value="">Select Patient</option>
          {patients.map(p => (
            <option key={p.patient_id} value={p.patient_id}>{p.first_name} {p.last_name}</option>
          ))}
        </select>

        {/* Dropdown para sa Doctor */}
        <select className="border p-2 rounded" value={selectedDoctor} onChange={e => setSelectedDoctor(e.target.value)} required>
          <option value="">Select Doctor</option>
          {doctors.map(d => (
            <option key={d.doctor_id} value={d.doctor_id}>Dr. {d.last_name}</option>
          ))}
        </select>

        <input type="datetime-local" className="border p-2 rounded" value={appDate} onChange={e => setAppDate(e.target.value)} required />
        
        <select className="border p-2 rounded" value={status} onChange={e => setStatus(e.target.value)}>
          <option value="Pending">Pending</option>
          <option value="Confirmed">Confirmed</option>
        </select>

        <button type="submit" className="bg-indigo-600 text-white p-2 rounded font-bold">Schedule</button>
      </form>

      <div className="bg-white rounded-xl shadow-md overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left">ID</th>
              <th className="px-6 py-3 text-left">Patient</th>
              <th className="px-6 py-3 text-left">Doctor</th>
              <th className="px-6 py-3 text-left">Date</th>
              <th className="px-6 py-3 text-center">Status</th>
            </tr>
          </thead>
          <tbody>
            {appointments.map((a: any) => (
              <tr key={a.appointment_id} className="border-b">
                <td className="px-6 py-4">#{a.appointment_id}</td>
                <td className="px-6 py-4">{a.patient}</td> 
                <td className="px-6 py-4">{a.doctor}</td>
                <td className="px-6 py-4">{new Date(a.appointment_date).toLocaleString()}</td>
                <td className="px-6 py-4 text-center">{a.status}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AppointmentList;
